local LFightIdleSkill = LxClass("LFightIdleSkill",nil)
-----------------------------------------------------------------
function LFightIdleSkill:LFightIdleSkill(obj,skillData,manager)
	---@type LFightIdleObject
	self._atkObj = obj
	self._skillData = skillData

	self._tarList = nil

	self._playEffList = skillData:GetPlayEffList()
	for i = #self._playEffList, 1, -1 do
		local data = self._playEffList[i]
		if data.playNum == 2 then
			-- 地板全屏特效
			table.remove(self._playEffList, i)
		end
	end

	---{index = {index=k,refId=v.refId,isPlay = true, startTime = time, endTime = v.playTime + time, isFinished=false, childList={}},... }
	self._playStateList = {}

	self._isSkillFinished = false

	self._startTime = nil

	self._isAniFinished = false

	self._heroOffectPointList = {
		[1] = 0.06,
		[2] = 0.12,
		[3] = 0.18,
		[4] = 0.24,
		[5] = 0.30,
	}

	self._manager = manager

	self._enableSound = false
	if manager.EnableSound then
		self._enableSound = manager:EnableSound()
	end
end
