	self._tarList = tarList
end

function LFightIdleSkill:EnableSpeedUp(bEnable,val)
	self._bSpeedUp = bEnable
	self._speedUpVal = val
end

function LFightIdleSkill:IsAniFinished()
	return self._isAniFinished
end

