-----------------------------------------------------------
function LFightIdleSkill:Start()
	self._startTime = nil
	self._isSkillFinished = false

	self:InitPlayState()
end

function LFightIdleSkill:InitPlayState()
	local playStateList = {}
	self._playStateList = playStateList
	local speedVal = 1
	if self._bSpeedUp then
		speedVal = 1 / self._speedUpVal
	end
	for k, v in ipairs(self._playEffList) do
		local playState = self:GeneratePlayState(k, v.refId, v.delayTime * speedVal, v.playTime * speedVal, 0)
		playState.isPlay = false
		playStateList[k] = playState
	end
end

function LFightIdleSkill:GeneratePlayState(index, refId, startTime, playTime, endTime)
	local playState = { index = index, refId = refId, isPlay = true, startTime = startTime, playTime=playTime, endTime = endTime, isFinished = false, childFinished = false, childList = {} ,leftEffects = nil}
	return playState
end

function LFightIdleSkill:GenerateChildPlayState(effData, startTime, playTime, endTime)
	local playState = { effData = effData, isPlay = false, startTime = startTime, playTime = playTime, endTime = endTime, isFinished = false }
	return playState
end

