function LFightIdleSkill:PreloadPlayList()
	for k, v in ipairs(self._playEffList) do
		self:DoPreloadEff(v)
	end
end

function LFightIdleSkill:DoPreloadEff(effData)
	local effType = effData.effType
	if effType == LSkillEffConst.PLAY_EFF_EFFECT then
		self:PreloadPlayEffect(effData)
	elseif effType == LSkillEffConst.PLAY_EFF_BULLET then
		self:PreloadPlayEffect(effData)
	end
end

function LFightIdleSkill:PreloadPlayEffect(effData)
	local effRes = effData.effRes --光效名字
	local playTime = effData.playTime --光效持续时间
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offset = effData.effOffsetStart --偏移

	local effectCtrl = self._manager:GetEffCtrl()
	local effTrans = self._manager:GetEffectRootTrans()
	local effect = effectCtrl:PreloadEffectObject(effTrans, effRes, Vector3.zero, LFightIdleConst.DIRECTION_LEFT, 0, playTime,dissipateTime)
end

