---播放动作
function LFightIdleSkill:ExecutePlayAni(effData,playState)
	local obj = self._atkObj
	--动作名字
	local ani = effData.effRes
	--动作时间
	local time = playState.playTime
	time = effData.actionReset == 0 and time or 0
	local speedUpVal = self._bSpeedUp and self._speedUpVal or nil
