---播放光效
function LFightIdleSkill:ExecutePlayEffect(effData,playState)
	local effRes = effData.effRes --光效名字
	local playTime = playState.playTime --光效持续时间
	local offset = effData.effOffsetStart --偏移
	local dissipateTime = effData.dissipateTime --光效消散时间
	local excursionIObject = effData.excursionIObject
	local speedUpVal = self._bSpeedUp and self._speedUpVal or nil
	local effectCtrl = self._manager:GetEffCtrl()

	local playNum = tonumber(effData.playNum)
	if playNum and playNum == 1 then
		local effect = effectCtrl:MakeEffectObject(self._manager:GetWndEffectRootTrans(), effRes, Vector3.zero, 0, 0, playTime, dissipateTime)
		effect:SetSpeedUpVal(speedUpVal)
		effect:SetScaleSize(140)
		effect:SetMaskShow(false)
		effect:SetLayerMask(LWnd.WND_LAYER)
		effectCtrl:AddEffect(effect)
		return
	end

	local obj = self._atkObj
	local bMask = obj:GetMaskShow()

	local dataList = self:CalcPlayEffectDataList(effData,playState)
	local offsetX = offset.x
	local offsetY = offset.y

	local targetObj = nil
	local boneName = effData.boneName
	if not string.isempty(boneName) then
		targetObj = obj
	end

	for k, v in ipairs(dataList) do
		local rootTrans = v.trans
		local dir = v.dir
		local pos = v.pos

		if dir == LFightIdleConst.DIRECTION_LEFT then
			pos.x = pos.x - offsetX
		else
			pos.x = pos.x + offsetX
		end
		pos.y = pos.y + offsetY
		pos.z = pos.z + offset.z

		---根据子弹落点
		if excursionIObject == 1 and playState.bulletTarPos then
			pos = playState.bulletTarPos
			pos.z = 0
		end

		local effect = effectCtrl:MakeEffectObject(rootTrans, effRes, pos, dir, 0, playTime, dissipateTime)
		effect:SetSpeedUpVal(speedUpVal)
		effect:SetScaleSize(v.scaleSize)
		effect:SetMaskShow(bMask)
		effect:SetBone(targetObj, boneName)
		effectCtrl:AddEffect(effect)
	end
end

---播放弹道
function LFightIdleSkill:ExecutePlayBullet(effData, playState)
	local obj = self._atkObj
	local effRes = effData.effRes --光效名字

	local moveSpeed = effData.moveSpeed * 0.01 -- 子弹飞行速度(配置表是像素这里要转换成米)
	local dissipateTime = effData.dissipateTime --光效消散时间
	local bulletTrack = effData.bulletTrack -- 子弹飞行轨迹
	local bulletCdTime = effData.bulletCdTime or 0 --多个子弹的延迟射出间隔
	local playNum = effData.playNum or {} --单个子弹分解次数
	local excursionIObject = effData.excursionIObject or 0
	local curBulletCdTime = 0

	local offsetStart = effData.effOffsetStart --偏移

	local offsetEnd = effData.effOffsetEnd

	local atkDir = obj:GetDirection()
	local atkPos = obj:GetPosition()

	local dataList = self:CalcPlayEffectDataList(effData,playState)

	local effectRootTrans = self._manager:GetEffectRootTrans()
	local effectPos

	local effectCtrl = self._manager:GetEffCtrl()

	--朝左
	if atkDir == LFightIdleConst.DIRECTION_LEFT then
		effectPos = Vector3(atkPos.x - offsetStart.x, atkPos.y + offsetStart.y, 0)
	else
		--朝右
		effectPos = Vector3(atkPos.x + offsetStart.x, atkPos.y + offsetStart.y, 0)
	end

	local scaleSize = obj:GetScaleSize()
	local bMask = obj:GetMaskShow()

	--子弹都是从自身位置创建，跟自身方向相同
	local moveTimeList = {}
	local maxMoveTime = 0

	local speedUpValRate = 1
	if self._bSpeedUp then
		speedUpValRate = 1 / self._speedUpVal
		moveSpeed = moveSpeed * self._speedUpVal
	end

	local bulletTarPosList = {}

	for k, v in ipairs(dataList) do
		local pos = v.pos

		--受击的 和 攻击的朝向相反的
		if atkDir == LFightIdleConst.DIRECTION_RIGHT then
			pos.x = pos.x - offsetEnd.x
		else
			pos.x = pos.x + offsetEnd.x
		end

		pos.y = pos.y + offsetEnd.y

		pos.z = 0

		-- 弹道落点列表
		local point = pos:Clone()
		bulletTarPosList[k] = point

		--计算出时间
		local moveTime = Vector3.Distance(effectPos, pos) / moveSpeed

		local effect = effectCtrl:MakeEffectObject(effectRootTrans, effRes, effectPos, atkDir, curBulletCdTime, moveTime,dissipateTime)
		effect:SetBullet(true, pos, moveTime, bulletTrack, k)
		effect:SetScaleSize(scaleSize)
		effect:SetMaskShow(bMask)
		effectCtrl:AddEffect(effect)

		moveTime = moveTime + curBulletCdTime
		if moveTime > maxMoveTime then
			maxMoveTime = moveTime
		end

		table.insert(moveTimeList, moveTime)

		if v.isSingleBulletMuti then
			bulletCdTime = k <= #playNum and playNum[k] or playNum[#playNum]
			-- 单个目标多个子弹的延迟射出间隔
			curBulletCdTime = curBulletCdTime + bulletCdTime
		else
			-- 多个目标的子弹的延迟射出间隔
			curBulletCdTime = curBulletCdTime + bulletCdTime
		end
	end

	local nextPlayList = effData.nextPlayList

	local childList = playState.childList
	if not childList then return end
	--不嵌套子列表

	local startTime = playState.startTime
	--计算子播放序列
	local effTarget = effData.effTarget
	if effTarget ~= LFightIdleConst.EFFECT_TO_EVERY_TAR then
		--整体时间轴
		for k, v in ipairs(nextPlayList) do
			local childStartTime = startTime + maxMoveTime + v.delayTime * speedUpValRate
			local childPlayState = self:GenerateChildPlayState(v, childStartTime, v.playTime * speedUpValRate,childStartTime + v.playTime * speedUpValRate)
			table.insert(childList, childPlayState)
		end
	else --单独时间轴 每个目标都不一样的
		local isShow = false
		local bulletTraPosListLen = #bulletTarPosList
		for k,v in ipairs(dataList) do
			local moveChildTime = moveTimeList[k]
			local obj = v.obj

			for k, childEff in ipairs(nextPlayList) do
				local childStartTime = startTime + moveChildTime + childEff.delayTime * speedUpValRate
				local childPlayState = self:GenerateChildPlayState(childEff, childStartTime, childEff.playTime * speedUpValRate,childStartTime + childEff.playTime * speedUpValRate)
				childPlayState.isSingle = true
				childPlayState.tarObj = obj
				table.insert(childList, childPlayState)
			end
		end
	end
end

