---屏幕抖动
function LFightIdleSkill:ExecutePlayScreenShake(effData)
	local time = effData.playTime
	local offsetEnd = effData.effOffsetEnd
	local intensityX = offsetEnd.x
	local intensityY = offsetEnd.y
	gLFightIdleManager:DoShake(time,intensityX,intensityY)
end

---播放被击与飘字
function LFightIdleSkill:ExecutePlayHitAndHud(effData,playState)
	local effType = effData.effType
	local bHit = effType == LSkillEffConst.PLAY_EFF_HIT_HUD
	local tarObjList
	local effTargetIndex = effData.effTargetIndex

	if playState.isSingle then
		--子弹命中后的飘字
		tarObjList = {playState.tarObj}
	else
		tarObjList = self._tarList
	end

	local skillRate = 0
	local skillData = self._skillData
	local calcData = skillData:GetSkillCalcData()
	local skillRateList = calcData.skillRateList
	local rateLen = #skillRateList
	if effTargetIndex > rateLen then
		skillRate = skillRateList[rateLen]
	else
		skillRate = skillRateList[1]
	end

	local effectType = calcData.effectType
	local bAlwaysCrit = calcData.bAlwaysCrit
	local hurtCalc = self._manager:GetHurtCalc()
	local obj = self._atkObj
	local skillCalcParams = {effectType=effectType,skillRate=skillRate,bHit=bHit, bAlwaysCrit=bAlwaysCrit}
	for k,v in ipairs(tarObjList or {} ) do
		if not v:IsDestroy() then
			if v:GetObjType() == LFightIdleConst.OBJ_MISSION then
				v:GetAI():ChangeAction(LFightIdleConst.ACTION_BEHIT)
				GF.ShakeMainScene(0.5,0.1,0.1)
			else
				hurtCalc:CalcHurt(obj,v,skillCalcParams)
			end
		end
	end
end

