---计算光效的挂载数据包括父节点，和坐标,坐标应该不能用原数据，需要自己新建一个 ，避免污染源对象
---返回 [{trans=effTrans, tarId = id|nil, pos=pos, dir = atkDir},...]
function LFightIdleSkill:CalcPlayEffectDataList(effData,playState)
	local obj = self._atkObj
	local effTarget = effData.effTarget --目标类型
	local effType = effData.effType
	local playNum = effData.playNum
	local effTargetIndex = effData.effTargetIndex
	local scaleSize = obj:GetScaleSize()

	local atkDir = obj:GetDirection()
	local side = obj:GetSide()
	local atkPos = obj:GetPosition()

	local dataList = {}
	if effTarget == LFightIdleConst.EFFECT_TO_SELF then
		--1=自身
		local dpTrans = obj:GetDpObject():GetDisplayTrans()
		local pos = obj:GetPosition():Clone()
		table.insert(dataList, { trans=dpTrans, pos = pos, obj = obj, dir = obj:GetDirection()})

	elseif effTarget == LFightIdleConst.EFFECT_TO_EVERY_TAR then
		if playState.isSingle then
			--直接用state中的列表,子弹命中之后发生的表演
			local tarObj = playState.tarObj
			if not tarObj:IsDestroy() then
				local pos = tarObj:GetPosition():Clone()
				table.insert(dataList, {
					trans = tarObj:GetDpObject():GetDisplayTrans(),
					obj=tarObj,
					pos = pos,
					dir = tarObj:GetDirection(),
				})
			end
		else
			--2=每一个目标
			local clientMulti = not table.isempty(playNum) and #playNum > 0  --一个攻击特效，多段伤害飘字表现

			-- 特殊多段子弹类型
			if effType == LSkillEffConst.PLAY_EFF_BULLET and clientMulti then
				local cnt = #playNum +1
				--for k, v in ipairs(self._tarList or {}) do
				--	local tarObj = v
				--	if not tarObj:IsDestroy() then
				--		local tarPos = tarObj:GetPosition()
				--		tarPos = tarPos:Clone()
				--		local tempData = { trans = tarObj:GetDpObject():GetDisplayTrans(), pos = tarPos, obj=tarObj, dir = tarObj:GetDirection()}
				--		table.insert(dataList, tempData)
				--	end
				--end
				local tarList = self._tarList or {}
				for k = 1 , cnt  do
					local tarObj = tarList[k] or tarList[1]
					if tarObj and  not tarObj:IsDestroy() then
						local tarPos = tarObj:GetPosition()
						tarPos = tarPos:Clone()
						local tempData = {
							trans = tarObj:GetDpObject():GetDisplayTrans(),
							pos = tarPos,
							obj=tarObj,
							dir = tarObj:GetDirection(),
							isSingleBulletMuti = true,
						}
						table.insert(dataList, tempData)
					end
				end
			else
				for k, v in ipairs(self._tarList or {}) do
					local tarObj = v
					if not tarObj:IsDestroy() then
						local tarPos = tarObj:GetPosition()
						tarPos = tarPos:Clone()
						local tempData = { trans = tarObj:GetDpObject():GetDisplayTrans(), pos = tarPos, obj=tarObj, dir = tarObj:GetDirection()}
						table.insert(dataList, tempData)
					end
				end
			end
		end
	elseif effTarget == LFightIdleConst.EFFECT_TO_CLICK_POS then
		local posTotal = self._clickPos or atkPos
		local rootTrans = self._manager:GetEffectRootTrans()
		table.insert(dataList, { trans = rootTrans, scaleSize = scaleSize,  pos = posTotal:Clone(), dir = atkDir})
	else
		--3=目标群体中心
		local tarList = self._tarList
		local posTotal = Vector3(0, 0, 0)
		local posLen = 0
		for k, v in ipairs(tarList) do
			local tarObj = v
			if not v:IsDestroy() then
				local tarPos = tarObj:GetPosition()
				posTotal.x = posTotal.x + tarPos.x
				posTotal.y = posTotal.y + tarPos.y
				posLen = posLen + 1
			end
		end
		if posLen > 0 then
			posTotal.x = posTotal.x / posLen
			posTotal.y = posTotal.y / posLen
		end

		local dir = atkDir
		if atkPos.x > posTotal.x then
			dir = LFightIdleConst.DIRECTION_LEFT
		end
		local rootTrans = self._manager:GetEffectRootTrans()
		table.insert(dataList, { trans = rootTrans, scaleSize = scaleSize,  pos = posTotal, dir = dir})
	end

	return dataList
end

------------------------------------------------------------------

function LFightIdleSkill:OnRun(time)
	if self._isDestroy then
		return false
	end

	if self._isSkillFinished then
		return false
	end

	if not self._startTime then
		self._startTime = time
	end

	if not self:CheckPlayList(time - self._startTime) then
		return true
	end

	self._isSkillFinished = true
	return false
end
-----------------------------------------------------------------
function LFightIdleSkill:IsDestroy()
	return self._isDestroy
end

function LFightIdleSkill:Destroy()
	table.removeall(self)
	self._isDestroy = true
end

return LFightIdleSkill

